using UnityEngine;

public class Enemy
{
    // Fields
    public string name;
    public int health;
    public int attackPower;
    private int maxHealth;  // Private field — only accessible inside this class

    // 1. Default constructor (no parameters)
    public Enemy()
    {
        name = "Unknown Enemy";
        health = 50;
        attackPower = 10;
        maxHealth = health;
        Debug.Log("Default enemy created!");
    }

    // 2. Parameterized constructor
    public Enemy(string enemyName, int enemyHealth, int enemyAttack)
    {
        name = enemyName;
        health = enemyHealth;
        attackPower = enemyAttack;
        maxHealth = enemyHealth;
        Debug.Log("Enemy " + name + " created!");
    }

    // 3. Constructor overloading (calling another constructor)
    public Enemy(string enemyName) : this(enemyName, 50, 10)
    {
        Debug.Log("Shortcut constructor for " + enemyName);
    }

    // Method to display enemy stats
    public void DisplayStats()
    {
        Debug.Log("=== " + name + " ===");
        Debug.Log("Health: " + health + "/" + maxHealth);
        Debug.Log("Attack: " + attackPower);
    }
}

public class ConstructorExample : MonoBehaviour
{
    void Start()
    {
        // Using default constructor
        Enemy defaultEnemy = new Enemy();
        defaultEnemy.DisplayStats();

        // Using parameterized constructor
        Enemy goblin = new Enemy("Goblin", 30, 8);
        goblin.DisplayStats();

        // Using overloaded constructor (calls the other one)
        Enemy skeleton = new Enemy("Skeleton");
        skeleton.DisplayStats();
    }
}

